import React, { useEffect, useRef } from 'react';
import { ArrowDown, FileText, FolderOpen } from 'lucide-react';
import { Button } from './ui/button';
import { personalInfo } from '../data/mock';
import Typed from 'typed.js';

const HeroSection = () => {
  const typedRef = useRef(null);
  const typedInstance = useRef(null);

  useEffect(() => {
    typedInstance.current = new Typed(typedRef.current, {
      strings: personalInfo.roles,
      typeSpeed: 50,
      backSpeed: 30,
      backDelay: 2000,
      loop: true,
      showCursor: true,
      cursorChar: '|'
    });

    return () => {
      typedInstance.current.destroy();
    };
  }, []);

  const scrollToSection = (sectionId) => {
    const element = document.getElementById(sectionId);
    if (element) {
      const offset = 80;
      const elementPosition = element.getBoundingClientRect().top;
      const offsetPosition = elementPosition + window.pageYOffset - offset;
      window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
    }
  };

  const handleDownloadResume = () => {
    const link = document.createElement('a');
    link.href = personalInfo.resumeUrl;
    link.download = 'Nihal_Singh_Resume.pdf';
    link.target = '_blank';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <section
      id="home"
      className="min-h-screen flex items-center justify-center relative bg-gradient-to-br from-neutral-50 via-white to-neutral-100"
    >
      {/* Subtle background pattern */}
      <div className="absolute inset-0 opacity-[0.015]">
        <div className="absolute inset-0" style={{
          backgroundImage: `radial-gradient(circle at 1px 1px, neutral-900 1px, transparent 0)`,
          backgroundSize: '40px 40px'
        }} />
      </div>

      <div className="relative z-10 max-w-6xl mx-auto px-6 lg:px-8 py-24 lg:py-32">
        <div className="grid lg:grid-cols-2 gap-12 items-center">
          {/* Text Content */}
          <div className="text-left order-2 lg:order-1">
            {/* Pretext */}
            <p className="text-neutral-500 text-lg mb-3 font-medium">
              {personalInfo.pretext}
            </p>

            {/* Name */}
            <h1 className="text-5xl sm:text-6xl lg:text-7xl font-bold text-neutral-900 mb-6 tracking-tight">
              {personalInfo.name}
            </h1>

            {/* Rotating subtitle */}
            <div className="h-12 sm:h-14 mb-8">
              <span className="text-2xl sm:text-3xl lg:text-4xl font-medium text-neutral-600">
                <span ref={typedRef}></span>
              </span>
            </div>

            {/* One-liner */}
            <p className="text-lg sm:text-xl text-neutral-500 max-w-2xl mb-10 leading-relaxed">
              {personalInfo.oneLiner}
            </p>

            {/* CTAs */}
            <div className="flex flex-col sm:flex-row gap-4">
              <Button
                onClick={handleDownloadResume}
                className="h-12 px-6 rounded-full bg-neutral-900 hover:bg-neutral-800 text-white font-medium transition-all hover:scale-105"
              >
                <FileText className="w-4 h-4 mr-2" />
                Download Resume
              </Button>
              <Button
                onClick={() => scrollToSection('projects')}
                variant="outline"
                className="h-12 px-6 rounded-full border-neutral-300 hover:bg-neutral-100 text-neutral-700 font-medium transition-all hover:scale-105"
              >
                <FolderOpen className="w-4 h-4 mr-2" />
                View Projects
              </Button>
            </div>
          </div>

          {/* Photo - Square with better fit */}
          <div className="order-1 lg:order-2 flex justify-center lg:justify-end">
            <div className="relative">
              <div className="w-64 h-64 sm:w-80 sm:h-80 lg:w-96 lg:h-96 rounded-2xl overflow-hidden border-4 border-white shadow-2xl">
                <img
                  src={personalInfo.photo}
                  alt={personalInfo.name}
                  className="w-full h-full object-cover object-top"
                />
              </div>
              {/* Decorative element */}
              <div className="absolute -bottom-4 -right-4 w-full h-full rounded-2xl border-2 border-neutral-200 -z-10" />
            </div>
          </div>
        </div>

        {/* Scroll indicator */}
        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 animate-bounce">
          <button
            onClick={() => scrollToSection('about')}
            className="p-2 rounded-full text-neutral-400 hover:text-neutral-600 transition-colors"
            aria-label="Scroll to About section"
          >
            <ArrowDown className="w-6 h-6" />
          </button>
        </div>
      </div>
    </section>
  );
};

export default HeroSection;
