import React, { useState } from 'react';
import { ChevronDown, ChevronUp } from 'lucide-react';
import { Badge } from './ui/badge';
import {
  project1, project1Bullets, project1Initiatives,
  project2, project2Bullets, project2Initiatives,
  project3, project3Initiatives, project3SubSection, project3SubItems,
  project4, project4Bullets, project4Initiatives
} from '../data/projectsData';

const ProjectsSection = () => {
  const [expandedSections, setExpandedSections] = useState(() => new Set([1]));

  const handleToggle = (sectionId, e) => {
    e.preventDefault();
    e.stopPropagation();
    setExpandedSections((prev) => {
      const next = new Set(prev);
      if (next.has(sectionId)) next.delete(sectionId);
      else next.add(sectionId);
      return next;
    });
  };

  return (
    <section id="projects" className="py-24 lg:py-32 bg-white">
      <div className="max-w-6xl mx-auto px-6 lg:px-8">
        <div className="mb-16">
          <h2 className="text-sm font-semibold text-neutral-400 uppercase tracking-wider mb-3">Projects</h2>
          <h3 className="text-3xl sm:text-4xl lg:text-5xl font-bold text-neutral-900 mb-6">What I've worked on</h3>
        </div>

        <div className="space-y-6">
          <Section1 isExpanded={expandedSections.has(1)} onToggle={(e) => handleToggle(1, e)} />
          <Section2 isExpanded={expandedSections.has(2)} onToggle={(e) => handleToggle(2, e)} />
          <Section3 isExpanded={expandedSections.has(3)} onToggle={(e) => handleToggle(3, e)} />
          <Section4 isExpanded={expandedSections.has(4)} onToggle={(e) => handleToggle(4, e)} />
        </div>
      </div>
    </section>
  );
};

const SectionHeader = ({ id, company, title, isExpanded, onToggle }) => (
  <button 
    type="button"
    onClick={onToggle} 
    className="w-full p-6 sm:p-8 flex items-center justify-between text-left hover:bg-neutral-100/50 transition-colors"
  >
    <div className="flex items-center gap-4">
      <span className="text-3xl sm:text-4xl font-bold text-neutral-200">{String(id).padStart(2, '0')}</span>
      <div>
        <Badge variant="secondary" className="bg-neutral-200 text-neutral-600 text-xs mb-2">{company}</Badge>
        <h4 className="text-xl sm:text-2xl font-bold text-neutral-900">{title}</h4>
      </div>
    </div>
    <div className="flex-shrink-0 ml-4">
      {isExpanded ? <ChevronUp className="w-6 h-6 text-neutral-400" /> : <ChevronDown className="w-6 h-6 text-neutral-400" />}
    </div>
  </button>
);

// Project image component — max height (max-h-96 = 384px, ~30% up from previous)
const ProjectImage = ({ src, alt, className = "" }) => (
  <div className={`rounded-lg overflow-hidden border border-neutral-200 bg-neutral-100 ${className}`}>
    <img src={src} alt={alt} className="w-full h-auto max-h-96 object-contain" />
  </div>
);

