import React, { useState } from 'react';
import { Mail, Linkedin, MapPin, Send, CheckCircle, Instagram } from 'lucide-react';
import { Button } from './ui/button';
import { Input } from './ui/input';
import { Textarea } from './ui/textarea';
import { personalInfo } from '../data/mock';

const ContactSection = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    message: ''
  });
  const [isSubmitted, setIsSubmitted] = useState(false);

  const handleSubmit = (e) => {
    e.preventDefault();

    // Gmail compose: to = your email, body = name, their email, and message
    const subject = encodeURIComponent(`Portfolio Contact from ${formData.name}`);
    const body = encodeURIComponent(
      `Name: ${formData.name}\nEmail (from): ${formData.email}\n\nMessage:\n${formData.message}`
    );
    const gmailUrl = `https://mail.google.com/mail/?view=cm&to=${encodeURIComponent(personalInfo.email)}&su=${subject}&body=${body}`;

    window.open(gmailUrl, '_blank', 'noopener,noreferrer');

    setIsSubmitted(true);
    setTimeout(() => {
      setIsSubmitted(false);
      setFormData({ name: '', email: '', message: '' });
    }, 3000);
  };

  const handleChange = (e) => {
    setFormData(prev => ({
      ...prev,
      [e.target.name]: e.target.value
    }));
  };


  return (
    <section id="contact" className="py-24 lg:py-32 bg-neutral-900">
      <div className="max-w-6xl mx-auto px-6 lg:px-8">
        <div className="mb-12">
          <h2 className="text-sm font-semibold text-neutral-500 uppercase tracking-wider mb-3">
            Contact
          </h2>
          <h3 className="text-3xl sm:text-4xl lg:text-5xl font-bold text-white mb-6">
            Let's connect
          </h3>
          <p className="text-lg text-neutral-400 max-w-2xl">
            Interested in discussing product strategy, marketplace dynamics, or just want to say hello? I'd love to hear from you.
          </p>
        </div>

        <div className="grid lg:grid-cols-2 gap-12 lg:gap-16">
          {/* Contact info */}
          <div className="space-y-8">
            {/* Email - Opens Gmail web compose */}
            <a
              href={`https://mail.google.com/mail/?view=cm&to=${encodeURIComponent(personalInfo.email)}`}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-4 group cursor-pointer"
              aria-label={`Send email to ${personalInfo.email}`}
            >
              <div className="w-12 h-12 rounded-full bg-neutral-800 flex items-center justify-center group-hover:bg-neutral-700 transition-colors">
                <Mail className="w-5 h-5 text-neutral-300" />
              </div>
              <div>
                <p className="text-sm text-neutral-500 mb-1">Email</p>
                <p className="text-white font-medium group-hover:text-neutral-300 transition-colors">
                  {personalInfo.email}
                </p>
              </div>
            </a>

            {/* LinkedIn */}
            <a
              href={personalInfo.linkedin}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-4 group"
            >
              <div className="w-12 h-12 rounded-full bg-neutral-800 flex items-center justify-center group-hover:bg-neutral-700 transition-colors">
                <Linkedin className="w-5 h-5 text-neutral-300" />
              </div>
              <div>
                <p className="text-sm text-neutral-500 mb-1">LinkedIn</p>
                <p className="text-white font-medium group-hover:text-neutral-300 transition-colors">
                  Connect with me
                </p>
              </div>
            </a>

            {/* Instagram */}
            <a
              href={personalInfo.instagram}
              target="_blank"
              rel="noopener noreferrer"
              className="flex items-center gap-4 group"
            >
              <div className="w-12 h-12 rounded-full bg-neutral-800 flex items-center justify-center group-hover:bg-neutral-700 transition-colors">
                <Instagram className="w-5 h-5 text-neutral-300" />
              </div>
              <div>
                <p className="text-sm text-neutral-500 mb-1">Instagram</p>
                <p className="text-white font-medium group-hover:text-neutral-300 transition-colors">
                  {personalInfo.instagramHandle}
                </p>
              </div>
            </a>

            {/* Location */}
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-full bg-neutral-800 flex items-center justify-center">
                <MapPin className="w-5 h-5 text-neutral-300" />
              </div>
              <div>
                <p className="text-sm text-neutral-500 mb-1">Location</p>
                <p className="text-white font-medium">
                  {personalInfo.location}
                </p>
              </div>
            </div>
          </div>

          {/* Contact form */}
          <div className="bg-neutral-800/50 rounded-2xl p-6 sm:p-8">
            {isSubmitted ? (
              <div className="flex flex-col items-center justify-center h-full py-8 text-center">
                <div className="w-16 h-16 rounded-full bg-green-500/20 flex items-center justify-center mb-4">
                  <CheckCircle className="w-8 h-8 text-green-400" />
                </div>
                <h4 className="text-xl font-semibold text-white mb-2">
                  Opening Gmail...
                </h4>
                <p className="text-neutral-400">
                  Complete sending the email to reach me!
                </p>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="space-y-5">
                <div>
                  <label htmlFor="name" className="block text-sm font-medium text-neutral-300 mb-2">
                    Name
                  </label>
                  <Input
                    id="name"
                    name="name"
                    type="text"
                    value={formData.name}
                    onChange={handleChange}
                    required
                    className="bg-neutral-700/50 border-neutral-600 text-white placeholder:text-neutral-500 focus:border-neutral-500 focus:ring-neutral-500"
                    placeholder="Your name"
                  />
                </div>

                <div>
                  <label htmlFor="email" className="block text-sm font-medium text-neutral-300 mb-2">
                    Email
                  </label>
                  <Input
                    id="email"
                    name="email"
                    type="email"
                    value={formData.email}
                    onChange={handleChange}
                    required
                    className="bg-neutral-700/50 border-neutral-600 text-white placeholder:text-neutral-500 focus:border-neutral-500 focus:ring-neutral-500"
                    placeholder="your@email.com"
                  />
                </div>

                <div>
                  <label htmlFor="message" className="block text-sm font-medium text-neutral-300 mb-2">
                    Message
                  </label>
                  <Textarea
                    id="message"
                    name="message"
                    value={formData.message}
                    onChange={handleChange}
                    required
                    rows={4}
                    className="bg-neutral-700/50 border-neutral-600 text-white placeholder:text-neutral-500 focus:border-neutral-500 focus:ring-neutral-500 resize-none"
                    placeholder="How can I help you?"
                  />
                </div>

                <Button
                  type="submit"
                  className="w-full h-12 rounded-full bg-white hover:bg-neutral-100 text-neutral-900 font-medium transition-all hover:scale-[1.02]"
                >
                  <Send className="w-4 h-4 mr-2" />
                  Send Message
                </Button>
              </form>
            )}
          </div>
        </div>
      </div>
    </section>
  );
};

export default ContactSection;
